import React from 'react';
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemText from '@material-ui/core/ListItemText';

const UnauthenticatedMenu = ({ categories }) => {
  // Funktion för att filtrera kategorierna och returnera de som har subMenyer med spelare
  const getFilteredCategories = (categories) => {
    const filteredCategories = [];
    for (const category of categories) {
      if (category.subMenu && category.subMenu.length > 0) {
        let hasPlayers = false;
        for (const subMenu of category.subMenu) {
          if (subMenu.players && subMenu.players.length > 0) {
            hasPlayers = true;
            break;
          }
        }
        if (hasPlayers) {
          filteredCategories.push(category);
        }
      }
    }
    return filteredCategories;
  };

  // Hämta filtrerade kategorier
  const filteredCategories = getFilteredCategories(categories);

  return (
    <div>
      {filteredCategories.map((category, index) => (
        <div key={index}>
          <ListItemText primary={category.mainMenu} />
          <List component="div" disablePadding>
            {category.subMenu.map((subItem, subIndex) => {
              if (subItem.players && subItem.players.length > 0) {
                return (
                  <ListItem key={`${category.mainMenu}-${subIndex}`} button>
                    <ListItemText primary={subItem} />
                  </ListItem>
                );
              }
              return null;
            })}
          </List>
        </div>
      ))}
    </div>
  );
};

export default UnauthenticatedMenu;
